  ('social-worker-moex-08260', 'social-worker', 'social-worker-moex-098-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據兒童及少年福利法雇主對年滿十五歲之少年員工應提供教育進修機會，其辦理績效良好者，那一個主管機關應予 獎勵？', '["衛生主管機關", "教育主管機關", "勞工主管機關", "社政主管機關"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "e78cbdae444d", "answer_pdf_sha1": "53304528ff4d", "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08261', 'social-worker', 'social-worker-moex-098-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '供應毒品、非法供應管制藥品或其他有害身心健康之物質予兒童及少年者，處新臺幣多少元罰鍰？', '["六萬元以上三十萬元以下", "六萬元以上十萬元以下", "十萬元以上三十萬元以下", "一萬元以上三十萬元以下"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "e78cbdae444d", "answer_pdf_sha1": "53304528ff4d", "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08262', 'social-worker', 'social-worker-moex-098-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '各級勞工主管機關應依身心障礙者之需求，自行或結合民間資源，提供無障礙個別化職業重建服務。前項所定職業重 建服務，不包含下列那一項服務？', '["職業輔導評量", "職業訓練", "微型創業基金", "就業服務"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "e78cbdae444d", "answer_pdf_sha1": "53304528ff4d", "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08263', 'social-worker', 'social-worker-moex-098-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '直轄市、縣（市）主管機關受理身心障礙者申請鑑定時，應交衛生主管機關指定相關機構或專業人員組成專業團隊， 進行鑑定並完成身心障礙鑑定報告。前項鑑定報告，至遲應於完成後幾日內送達申請人戶籍所在地之衛生主管機關？', '["十日內", "二十日內", "三十日內", "沒有明文規定"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "e78cbdae444d", "answer_pdf_sha1": "53304528ff4d", "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08264', 'social-worker', 'social-worker-moex-098-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '主管機關應遴聘（派）身心障礙者或其監護人代表、身心障礙福利學者或專家、民意代表與民間相關機構、團體代表 及各目的事業主管機關代表辦理身心障礙者權益保障事項；其中遴聘身心障礙者或其監護人代表及民間相關機構、團 體代表之比例，不得少於三分之一。前項之代表，單一性別不得少於多少？', '["二分之一", "三分之一", "四分之一", "五分之一"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "e78cbdae444d", "answer_pdf_sha1": "53304528ff4d", "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08265', 'social-worker', 'social-worker-moex-098-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '家庭暴力防治法之通常保護令失效前，法院得依當事人或被害人之聲請撤銷、變更或延長之。延長之期間為何？', '["一年以下，並以一次為限", "二年以下，並以一次為限", "三年以下，並以一次為限", "沒有限制"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "e78cbdae444d", "answer_pdf_sha1": "53304528ff4d", "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08266', 'social-worker', 'social-worker-moex-098-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '胎兒出生後七日內，接生人應將其出生之相關資料通報戶政及衛生主管機關備查。非以網路通報或郵寄者，以那一日 為通報日？', '["胎兒實際出生日", "主管機關收受日", "主管機關公告日", "法院公告日"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "e78cbdae444d", "answer_pdf_sha1": "53304528ff4d", "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 11, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08267', 'social-worker', 'social-worker-moex-098-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '私立社會救助機構停辦或決議解散時，主管機關對於該機構收容之人應即予以適當之安置，社會救助機構應予接受； 不予接受者，強制實施之，並處以新臺幣多少罰鍰？', '["三萬元以上六十萬元以下", "六萬元以上六十萬元以下", "六萬元以上五十萬元以下", "六萬元以上十萬元以下"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "e78cbdae444d", "answer_pdf_sha1": "53304528ff4d", "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 12, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
