  ('social-worker-moex-08269', 'social-worker', 'social-worker-moex-098-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '死亡而無遺屬與遺產者，應由那個機關辦理葬埋？', '["地方鄰里長及里辦公室", "當地鄉（鎮、市、區）公所", "縣市政府", "內政部社會司 （請接背面） 律師、會計師、社會工作師 全一張 98年專門職業及技術人員高等考試 考試試題  代號：9 0230 不動產估價師、專利師 （背面） 類    科： 社會工作師"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "e78cbdae444d", "answer_pdf_sha1": "53304528ff4d", "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
